mapper.select:
select log_id, company_id, user_id, action, action_description, entity_type, entity_id, detail, created_at
from activity_logs
where log_id = #{logId,jdbcType=VARCHAR}

select log_id, company_id, user_id, action, action_description, entity_type, entity_id, detail, created_at
from activity_logs
where user_id = #{userId,jdbcType=VARCHAR}
order by created_at desc
limit #{limit} offset #{offset}

select count(*)
from activity_logs
where user_id = #{userId,jdbcType=VARCHAR}
